import{c as s,Q as a,j as i,m as t}from"./chunks/framework.CLEOx5cX.js";const k=JSON.parse('{"title":"FAQ and Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/oskar-battlepass/faq-and-troubleshooting.md","filePath":"scripts/oskar-battlepass/faq-and-troubleshooting.md","lastUpdated":1780286698000}'),l={name:"scripts/oskar-battlepass/faq-and-troubleshooting.md"};function o(n,e,r,h,p,d){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="faq-and-troubleshooting" tabindex="-1">FAQ and Troubleshooting <a class="header-anchor" href="#faq-and-troubleshooting" aria-label="Permalink to &quot;FAQ and Troubleshooting&quot;">​</a></h1><p>Common installation, configuration, and integration issues for <code>oskar_battlepass</code>.</p><h2 id="the-battle-pass-does-not-open" tabindex="-1">The Battle Pass Does Not Open <a class="header-anchor" href="#the-battle-pass-does-not-open" aria-label="Permalink to &quot;The Battle Pass Does Not Open&quot;">​</a></h2><p>Check:</p><ul><li>The resource is started.</li><li>The command is correct in <code>config.command</code>.</li><li>The selected framework starts before <code>oskar_battlepass</code>.</li><li>The NUI build exists in <code>web/build</code>.</li><li>The client console has no JavaScript or Lua errors.</li></ul><p>Default command:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/passe</span></span></code></pre></div><h2 id="framework-resource-not-found" tabindex="-1">Framework Resource Not Found <a class="header-anchor" href="#framework-resource-not-found" aria-label="Permalink to &quot;Framework Resource Not Found&quot;">​</a></h2><p>If the console says the framework resource cannot be found, check:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">framework </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;qbcore&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">frameworkSettings.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qbcore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resource</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;qb-core&#39;</span></span></code></pre></div><p>Change <code>resource</code> to your real framework resource name.</p><h2 id="player-is-not-premium" tabindex="-1">Player Is Not Premium <a class="header-anchor" href="#player-is-not-premium" aria-label="Permalink to &quot;Player Is Not Premium&quot;">​</a></h2><p>Premium is group-based. Confirm:</p><ul><li>The player has group <code>PassePremium</code>.</li><li>The selected adapter returns the player groups correctly.</li><li><code>BP.PlayerHasGroup(source, groupName)</code> can see that group.</li><li><code>premiumAccess.group</code> matches the group used by your base.</li></ul><h2 id="premium-xp-boost-does-not-apply" tabindex="-1">Premium XP Boost Does Not Apply <a class="header-anchor" href="#premium-xp-boost-does-not-apply" aria-label="Permalink to &quot;Premium XP Boost Does Not Apply&quot;">​</a></h2><p>Check:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">premiumAccess </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  group </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;PassePremium&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  xpMultiplier </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The same group controls premium rewards and XP boost.</p><h2 id="mission-progress-does-not-update" tabindex="-1">Mission Progress Does Not Update <a class="header-anchor" href="#mission-progress-does-not-update" aria-label="Permalink to &quot;Mission Progress Does Not Update&quot;">​</a></h2><p>Confirm the external job script triggers:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">TriggerEvent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;oskar_battlepass:jobPayment&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, amount, taskCategory, source)</span></span></code></pre></div><p>Also confirm:</p><ul><li><code>taskCategory</code> matches a task in <code>config.tasks</code>.</li><li><code>source</code> is the player source.</li><li>The player has the required level for that mission.</li><li>The mission is not already completed.</li></ul><h2 id="store-item-gives-too-many-items" tabindex="-1">Store Item Gives Too Many Items <a class="header-anchor" href="#store-item-gives-too-many-items" aria-label="Permalink to &quot;Store Item Gives Too Many Items&quot;">​</a></h2><p>Check:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">storePurchase </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  useItemAmountAsBase </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>With this default, quantity <code>1</code> gives one item. If this is set to <code>true</code>, the script uses legacy pack behavior:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>final amount = itemAmount * selected quantity</span></span></code></pre></div><h2 id="store-item-cannot-be-bought" tabindex="-1">Store Item Cannot Be Bought <a class="header-anchor" href="#store-item-cannot-be-bought" aria-label="Permalink to &quot;Store Item Cannot Be Bought&quot;">​</a></h2><p>Check:</p><ul><li>The item exists in <code>config.store</code>.</li><li>The item exists in your inventory.</li><li>The player has enough <code>diamante</code>.</li><li>The selected framework adapter can remove <code>diamante</code>.</li><li><code>functions/store.lua</code> is loaded before <code>functions/server.lua</code>.</li></ul><h2 id="box-is-not-consumed" tabindex="-1">Box Is Not Consumed <a class="header-anchor" href="#box-is-not-consumed" aria-label="Permalink to &quot;Box Is Not Consumed&quot;">​</a></h2><p>The internal box inventory must be updated when opening a box. Confirm:</p><ul><li>The player owns that box type.</li><li>The open-box callback removes one box before reward delivery.</li><li>The UI refreshes after opening.</li><li>There is no server error in the box callback.</li></ul><h2 id="box-reward-only-arrives-after-closing" tabindex="-1">Box Reward Only Arrives After Closing <a class="header-anchor" href="#box-reward-only-arrives-after-closing" aria-label="Permalink to &quot;Box Reward Only Arrives After Closing&quot;">​</a></h2><p>The expected behavior is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>countdown finishes -&gt; reward delivered -&gt; box already consumed</span></span></code></pre></div><p>If reward delivery waits for the close button, check the client open-box flow and the server callback that finalizes the box reward.</p><h2 id="profile-image-does-not-use-instapic" tabindex="-1">Profile Image Does Not Use Instapic <a class="header-anchor" href="#profile-image-does-not-use-instapic" aria-label="Permalink to &quot;Profile Image Does Not Use Instapic&quot;">​</a></h2><p>Check:</p><ul><li><code>lb-phone</code> is started.</li><li><code>useLbPhoneInstapic = true</code>.</li><li>The player has a phone row in <code>phone_phones</code>.</li><li><code>phone_phones.id</code> matches the player license.</li><li><code>phone_instagram_accounts.profile_image</code> is not empty.</li></ul><p>Fallback image:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaultImage </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;images/jimmy_pic.webp&#39;</span></span></code></pre></div><h2 id="ui-still-has-old-yellow-hover-color" tabindex="-1">UI Still Has Old Yellow Hover Color <a class="header-anchor" href="#ui-still-has-old-yellow-hover-color" aria-label="Permalink to &quot;UI Still Has Old Yellow Hover Color&quot;">​</a></h2><p>Search the NUI styles for hardcoded yellow values and replace them with configured primary color usage.</p><p>Use:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaultColors </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  primaryColor </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;rgb(96, 65, 180)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  rawPrimaryColor </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;96, 65, 180&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="reward-can-be-claimed-twice-with-fast-clicks" tabindex="-1">Reward Can Be Claimed Twice With Fast Clicks <a class="header-anchor" href="#reward-can-be-claimed-twice-with-fast-clicks" aria-label="Permalink to &quot;Reward Can Be Claimed Twice With Fast Clicks&quot;">​</a></h2><p>Reward claims must be locked server-side. Confirm the server validates:</p><ul><li>The reward exists.</li><li>The player has the required level.</li><li>The reward was not already claimed.</li><li>A temporary claim lock is active during processing.</li></ul><h2 id="oxmysql-error" tabindex="-1">oxmysql Error <a class="header-anchor" href="#oxmysql-error" aria-label="Permalink to &quot;oxmysql Error&quot;">​</a></h2><p>ESX, QBCore, QBox, and SQL-backed storage require <code>oxmysql</code>.</p><p>Start order:</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ensure oxmysql</span></span>
<span class="line"><span>ensure oskar_battlepass</span></span></code></pre></div><h2 id="release-checklist" tabindex="-1">Release Checklist <a class="header-anchor" href="#release-checklist" aria-label="Permalink to &quot;Release Checklist&quot;">​</a></h2><ul><li>Framework selector is correct.</li><li>Open <code>functions/</code> files are included.</li><li>Open <code>frameworks/</code> files are included.</li><li>Protected files are not required for customer edits.</li><li>The active catalog has 30 normal and 30 premium rewards.</li><li>Mission XP total matches 3000 XP.</li><li>Diamond shop is repeatable.</li><li>Boxes are legal-only and consume correctly.</li><li>Premium group grants rewards and XP boost.</li><li>Profile image fallback works.</li></ul>`,56)])])}const u=s(l,[["render",o]]);export{k as __pageData,u as default};
